import org.apache.kafka.clients.producer.KafkaProducer;
import org.apache.kafka.clients.producer.ProducerRecord;
import org.apache.kafka.common.header.Header;
import org.apache.kafka.common.header.Headers;

public class KafkaProducerExample {
    public static void main(String[] args) {
        // Create a producer instance
        KafkaProducer<String, String> producer = new KafkaProducer<>(
                new Properties() {{
                    put("bootstrap.servers", "localhost:9092");
                    put("key.serializer", "org.apache.kafka.common.serialization.StringSerializer");
                    put("value.serializer", "org.apache.kafka.common.serialization.StringSerializer");
                }}
        );

        // Create a producer record with headers
        ProducerRecord<String, String> record = new ProducerRecord<>("my-topic", "Hello Kafka!");
        Headers headers = new Headers();
        headers.add("tracking-id", "123456789");
        headers.add("user-id", "John Doe");
        headers.add("custom-metadata", "Some custom metadata");
        record.headers(headers);

        // Send the producer record to the Kafka topic
        producer.send(record, (recordMetadata, e) -> {
            if (e != null) {
                System.out.println("Failed to send message: " + e);
            } else {
                System.out.println("Message sent successfully: " + recordMetadata);
            }
        });
    }
}